const transactions = [
  { id: 1, type: 'deposit' },
  { id: 2, type: 'withdrawal' },
  { id: 3, type: 'deposit' },
  { id: 4, type: 'withdrawal' },
];

// Old way
const last = [...transactions]
  .reverse()
  .find(t =&gt; t.type === 'deposit');

// New way
const last = transactions
  .findLast(t =&gt; t.type === 'deposit');
// { id: 3, type: 'deposit' }

const colors = ['red', 'green', 'blue'];

// Old way
colors[colors.length - 1]; // 'blue'
colors[colors.length - 2]; // 'green'

// New way
colors.at(-1);  // 'blue'
colors.at(-2);  // 'green'
colors.at(0);   // 'red'

// Works on strings too
'hello'.at(-1); // 'o'

const arr = [1, 2, 3, 4, 5];

// Old way (mutates!)
const copy = [...arr];
copy[2] = 99;

// New way (immutable)
const updated = arr.with(2, 99);
// [1, 2, 99, 4, 5]

// Original unchanged
console.log(arr);
// [1, 2, 3, 4, 5]

const scores = [40, 10, 90, 30];

// Old way (mutates!)
const sorted = [...scores].sort(
  (a, b) =&gt; a - b
);

// New way (immutable)
const sorted = scores.toSorted(
  (a, b) =&gt; a - b
);
// [10, 30, 40, 90]

// Original unchanged
console.log(scores);
// [40, 10, 90, 30]

const steps = ['start', 'process', 'end'];

// Old way (mutates!)
const reversed = [...steps].reverse();

// New way (immutable)
const reversed = steps.toReversed();
// ['end', 'process', 'start']

// Original unchanged
console.log(steps);
// ['start', 'process', 'end']
